(405, 'woocommerce_marketplace_suggestions', 'a:2:{s:11:\"suggestions\";a:27:{i:0;a:1:{s:21:\"recommendations-count\";i:5;}i:1;a:4:{s:4:\"slug\";s:28:\"product-edit-meta-tab-header\";s:7:\"context\";a:1:{i:0;s:28:\"product-edit-meta-tab-header\";}s:5:\"title\";s:22:\"Recommended extensions\";s:13:\"allow-dismiss\";b:0;}i:2;a:7:{s:4:\"slug\";s:39:\"product-edit-meta-tab-footer-browse-all\";s:7:\"context\";a:1:{i:0;s:28:\"product-edit-meta-tab-footer\";}s:9:\"link-text\";s:21:\"Discover more options\";s:3:\"url\";s:64:\"https://woocommerce.com/product-category/woocommerce-extensions/\";s:7:\"iam-url\";s:55:\"admin.php?page=wc-admin&tab=extensions&path=/extensions\";s:8:\"promoted\";s:31:\"category-woocommerce-extensions\";s:13:\"allow-dismiss\";b:0;}i:3;a:4:{s:4:\"slug\";s:19:\"orders-empty-header\";s:7:\"context\";a:1:{i:0;s:24:\"orders-list-empty-header\";}s:5:\"title\";s:20:\"Tools for your store\";s:13:\"allow-dismiss\";b:0;}i:4;a:7:{s:4:\"slug\";s:30:\"orders-empty-footer-browse-all\";s:7:\"context\";a:1:{i:0;s:24:\"orders-list-empty-footer\";}s:9:\"link-text\";s:21:\"Discover more options\";s:3:\"url\";s:64:\"https://woocommerce.com/product-category/woocommerce-extensions/\";s:7:\"iam-url\";s:55:\"admin.php?page=wc-admin&tab=extensions&path=/extensions\";s:8:\"promoted\";s:31:\"category-woocommerce-extensions\";s:13:\"allow-dismiss\";b:0;}i:5;a:4:{s:4:\"slug\";s:35:\"products-empty-header-product-types\";s:7:\"context\";a:1:{i:0;s:26:\"products-list-empty-header\";}s:5:\"title\";s:23:\"Other types of products\";s:13:\"allow-dismiss\";b:0;}i:6;a:7:{s:4:\"slug\";s:32:\"products-empty-footer-browse-all\";s:7:\"context\";a:1:{i:0;s:26:\"products-list-empty-footer\";}s:9:\"link-text\";s:21:\"Discover more options\";s:3:\"url\";s:64:\"https://woocommerce.com/product-category/woocommerce-extensions/\";s:7:\"iam-url\";s:55:\"admin.php?page=wc-admin&tab=extensions&path=/extensions\";s:8:\"promoted\";s:31:\"category-woocommerce-extensions\";s:13:\"allow-dismiss\";b:0;}i:7;a:9:{s:4:\"slug\";s:42:\"orders-list-empty-body-table-rate-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:19:\"table-rate-shipping\";s:4:\"icon\";s:101:\"https://woocommerce.com/wp-content/uploads/2012/07/Table_Rate_Shipping_icon-marketplace-160x160-2.png\";s:5:\"title\";s:19:\"Table Rate Shipping\";s:4:\"copy\";s:123:\"Advanced, flexible shipping. Define multiple shipping rates based on location, price, weight, shipping class or item count.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:53:\"https://woocommerce.com/products/table-rate-shipping/\";s:9:\"is_pinned\";b:1;}i:8;a:9:{s:4:\"slug\";s:56:\"orders-list-empty-body-conditional-shipping-and-payments\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:33:\"conditional-shipping-and-payments\";s:4:\"icon\";s:111:\"https://woocommerce.com/wp-content/uploads/2015/03/Conditional_Shipping_Payments_icon-marketplace-160x160-1.png\";s:5:\"title\";s:33:\"Conditional Shipping and Payments\";s:4:\"copy\";s:91:\"Use conditional logic to restrict the shipping and payment options available on your store.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:67:\"https://woocommerce.com/products/conditional-shipping-and-payments/\";s:9:\"is_pinned\";b:1;}i:9;a:9:{s:4:\"slug\";s:40:\"orders-list-empty-body-shipment-tracking\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:17:\"shipment-tracking\";s:4:\"icon\";s:99:\"https://woocommerce.com/wp-content/uploads/2012/05/Shipment_Tracking_icon-marketplace-160x160-2.png\";s:5:\"title\";s:17:\"Shipment Tracking\";s:4:\"copy\";s:49:\"Add shipment tracking information to your orders.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:51:\"https://woocommerce.com/products/shipment-tracking/\";s:9:\"is_pinned\";b:1;}i:10;a:8:{s:4:\"slug\";s:40:\"orders-list-empty-body-local-pickup-plus\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:17:\"local-pickup-plus\";s:4:\"icon\";s:78:\"https://woocommerce.com/wp-content/uploads/2015/06/skyverge-wc-icon-b2vhw6.png\";s:5:\"title\";s:17:\"Local Pickup Plus\";s:4:\"copy\";s:135:\"Let customers buy online and pick up in-store with options to pick up products from specific locations, select a pickup date, and more.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:51:\"https://woocommerce.com/products/local-pickup-plus/\";}i:11;a:8:{s:4:\"slug\";s:67:\"orders-list-empty-body-estimated-delivery-date-time-for-woocommerce\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:44:\"estimated-delivery-date-time-for-woocommerce\";s:4:\"icon\";s:87:\"https://woocommerce.com/wp-content/uploads/2021/07/Estimated-Delivery-Time-white-01.png\";s:5:\"title\";s:30:\"Estimated Delivery Date & Time\";s:4:\"copy\";s:134:\"Display estimated delivery time on your shop, product, cart, and checkout pages. Option to show estimated delivery date by city/state.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:78:\"https://woocommerce.com/products/estimated-delivery-date-time-for-woocommerce/\";}i:12;a:8:{s:4:\"slug\";s:58:\"orders-list-empty-body-role-based-payment-shipping-methods\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:35:\"role-based-payment-shipping-methods\";s:4:\"icon\";s:83:\"https://woocommerce.com/wp-content/uploads/2012/08/role-based-methods-copy@0.5x.png\";s:5:\"title\";s:37:\"Role-Based Payment / Shipping Methods\";s:4:\"copy\";s:76:\"Limit different user roles to specific payment methods and shipping methods.\";s:11:\"button-text\";s:10:\"Learn More\";s:3:\"url\";s:69:\"https://woocommerce.com/products/role-based-payment-shipping-methods/\";}i:13;a:8:{s:4:\"slug\";s:45:\"orders-list-empty-body-flat-rate-box-shipping\";s:7:\"context\";s:22:\"orders-list-empty-body\";s:7:\"product\";s:22:\"flat-rate-box-shipping\";s:4:\"icon\";s:104:\"https://woocommerce.com/wp-content/uploads/2013/04/Flat_Rate_Box_Shipping_icon-marketplace-160x160-1.png\";s:5:\"title\";s:22:\"Flat Rate